import{c as n,S as t,j as h,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Học liệu, giáo trình","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/hoc-lieu.md","filePath":"hoc-vien/hoc-lieu.md","lastUpdated":0}'),o={name:"hoc-vien/hoc-lieu.md"};function r(l,i,c,e,g,u){return t(),h("div",null,[...i[0]||(i[0]=[a('<h1 id="hoc-lieu-giao-trinh" tabindex="-1">Học liệu, giáo trình <a class="header-anchor" href="#hoc-lieu-giao-trinh" aria-label="Permalink to “Học liệu, giáo trình”">​</a></h1><p>Học liệu là <strong>tài liệu đọc / nghe</strong> (sách, ebook, slide, audio) dùng cho học tập, tham khảo. Khác với khóa học (có cấu trúc bài giảng + đề thi), học liệu là <strong>tài nguyên độc lập</strong>.</p><h2 id="cac-loai-hoc-lieu" tabindex="-1">Các loại học liệu <a class="header-anchor" href="#cac-loai-hoc-lieu" aria-label="Permalink to “Các loại học liệu”">​</a></h2><table tabindex="0"><thead><tr><th>Loại</th><th>Ví dụ</th></tr></thead><tbody><tr><td><strong>Sách điện tử (PDF/EPUB)</strong></td><td>&quot;Sổ tay Toán 12&quot;, &quot;Cẩm nang HSA 2026&quot;</td></tr><tr><td><strong>Slide bài giảng</strong></td><td>File PPT của giáo viên</td></tr><tr><td><strong>Đề kèm lời giải</strong></td><td>Đề + lời giải chi tiết (PDF)</td></tr><tr><td><strong>Audio / Podcast học</strong></td><td>Bản đọc luyện nghe tiếng Anh</td></tr><tr><td><strong>Video giảng dạng dài</strong></td><td>Buổi livestream record</td></tr><tr><td><strong>Tài liệu tham khảo</strong></td><td>Tài liệu môn chuyên</td></tr></tbody></table><h2 id="tim-hoc-lieu-o-đau" tabindex="-1">Tìm học liệu ở đâu? <a class="header-anchor" href="#tim-hoc-lieu-o-đau" aria-label="Permalink to “Tìm học liệu ở đâu?”">​</a></h2><h3 id="trang-chu" tabindex="-1">Trang chủ <a class="header-anchor" href="#trang-chu" aria-label="Permalink to “Trang chủ”">​</a></h3><ul><li>Mục <strong>&quot;Học liệu, giáo trình&quot;</strong>.</li></ul><h3 id="menu-đieu-huong" tabindex="-1">Menu điều hướng <a class="header-anchor" href="#menu-đieu-huong" aria-label="Permalink to “Menu điều hướng”">​</a></h3><ul><li>Bấm <strong>Học liệu</strong> → lọc theo môn / kỳ thi.</li></ul><h3 id="kem-trong-khoa-hoc" tabindex="-1">Kèm trong khóa học <a class="header-anchor" href="#kem-trong-khoa-hoc" aria-label="Permalink to “Kèm trong khóa học”">​</a></h3><ul><li>Nhiều khóa có <strong>học liệu kèm miễn phí</strong> ở tab Tài liệu.</li></ul><h2 id="trang-chi-tiet-hoc-lieu" tabindex="-1">Trang chi tiết học liệu <a class="header-anchor" href="#trang-chi-tiet-hoc-lieu" aria-label="Permalink to “Trang chi tiết học liệu”">​</a></h2><p>Hiển thị:</p><ul><li>Ảnh bìa</li><li>Tên, tác giả / giáo viên</li><li>Mô tả, mục lục</li><li>Định dạng (PDF, MP3, MP4...)</li><li>Giá (miễn phí / có phí)</li><li><strong>Xem thử</strong>: 1-2 chương đầu hoặc 30 giây audio.</li><li>Nút <strong>Mua / Tải về</strong>.</li></ul><h2 id="mua-hoc-lieu" tabindex="-1">Mua học liệu <a class="header-anchor" href="#mua-hoc-lieu" aria-label="Permalink to “Mua học liệu”">​</a></h2><ul><li>Tương tự mua khóa học (xem <a href="./mua-khoa-hoc">Mua khóa học</a>).</li><li>Sau khi thanh toán, học liệu xuất hiện trong <strong>Khóa học của tôi → tab Học liệu</strong> (hoặc khu vực Học liệu riêng).</li></ul><h2 id="đoc-tai-ve" tabindex="-1">Đọc / Tải về <a class="header-anchor" href="#đoc-tai-ve" aria-label="Permalink to “Đọc / Tải về”">​</a></h2><h3 id="sach-pdf" tabindex="-1">Sách PDF <a class="header-anchor" href="#sach-pdf" aria-label="Permalink to “Sách PDF”">​</a></h3><ul><li><strong>Đọc online</strong>: trang trình bày có Zoom, chia trang, full screen.</li><li><strong>Tải về</strong> (nếu cho phép): file lưu trên máy.</li><li>Một số sách có <strong>DRM</strong> (bảo vệ bản quyền): chỉ đọc trong app, không tải.</li></ul><h3 id="audio" tabindex="-1">Audio <a class="header-anchor" href="#audio" aria-label="Permalink to “Audio”">​</a></h3><ul><li>Trình phát nhúng: play, pause, đổi tốc độ.</li><li>Có thể tải về MP3.</li></ul><h3 id="video" tabindex="-1">Video <a class="header-anchor" href="#video" aria-label="Permalink to “Video”">​</a></h3><ul><li>Tương tự bài giảng video (xem <a href="./hoc-bai-giang">Học bài giảng</a>).</li></ul><h2 id="đanh-dau-ghi-chu" tabindex="-1">Đánh dấu, ghi chú <a class="header-anchor" href="#đanh-dau-ghi-chu" aria-label="Permalink to “Đánh dấu, ghi chú”">​</a></h2><p>Trong trình đọc PDF (nếu hệ thống hỗ trợ):</p><ul><li><strong>Highlight</strong> đoạn quan trọng (4 màu).</li><li><strong>Note</strong> ghi chú riêng trên trang.</li><li><strong>Bookmark</strong> trang quan trọng để dễ quay lại.</li></ul><p>Note + highlight được lưu trên tài khoản, đồng bộ giữa các thiết bị.</p><h2 id="tim-kiem-trong-hoc-lieu" tabindex="-1">Tìm kiếm trong học liệu <a class="header-anchor" href="#tim-kiem-trong-hoc-lieu" aria-label="Permalink to “Tìm kiếm trong học liệu”">​</a></h2><ul><li>Trong trình đọc, <strong>Ctrl + F</strong> (Cmd + F trên Mac) để tìm từ khóa.</li><li>Một số học liệu có <strong>mục lục thông minh</strong> - bấm chương để nhảy nhanh.</li></ul><h2 id="in-sach" tabindex="-1">In sách <a class="header-anchor" href="#in-sach" aria-label="Permalink to “In sách”">​</a></h2><ul><li>Một số sách cho phép in (có nút <strong>In</strong>).</li><li>Lưu ý: dung lượng in lớn, hãy chọn <strong>các chương cần thiết</strong> thay vì in cả sách.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi mua sách nhưng không thấy nút &quot;Tải về&quot;?</strong> → Sách có DRM, chỉ đọc online. Vẫn dùng được trên app / web khi đăng nhập.</p><p><strong>Tôi tải xong file PDF nhưng không mở được?</strong> → Cần ứng dụng đọc PDF (Adobe Reader, Foxit, hoặc trình duyệt). Đảm bảo file tải đầy đủ (không bị ngắt giữa chừng).</p><p><strong>Tôi muốn copy text trong sách để gõ ghi chú?</strong> → Tùy sách. Nếu sách bị khóa copy, hãy dùng <strong>chức năng Note trong trình đọc</strong>.</p><p><strong>Học liệu này có cập nhật khi sang năm mới không?</strong> → Tùy nhà phát hành. Một số sách số có <strong>bản cập nhật miễn phí</strong>, một số bán năm nào dùng năm đó.</p><p><strong>Tôi muốn chia sẻ học liệu cho bạn.</strong> → Học liệu có bản quyền - không nên chia sẻ. Mỗi tài khoản tự mua và sử dụng.</p>',37)])])}const m=n(o,[["render",r]]);export{d as __pageData,m as default};
